const axios = require('axios');
const db = require('./db');

async function connectDatabase(connectionString) {
  try {
    const connection = await db.connect(connectionString);
    return {connection};
  } catch (error) {
    return {error: {code: error.code || 'ECONNREFUSED', message: error.message}};
  }
}

async function fetchData(url, options = {}) {
  try {
    const response = await axios.get(url, options);
    return {data: response.data};
  } catch (error) {
    const errorType = error.code === 'ECONNABORTED' || error.message.includes('timeout') 
      ? 'timeout' 
      : 'network';
    return {error: {type: errorType, message: error.message}};
  }
}

function parseResponse(responseText) {
  try {
    const data = JSON.parse(responseText);
    return {data};
  } catch (error) {
    return {error: error, data: null};
  }
}

function validateInput(input) {
  if (!input.name || !input.email) {
    return {valid: false};
  }
  return {valid: true};
}

module.exports = {
  connectDatabase,
  fetchData,
  parseResponse,
  validateInput
};
